def transition(state, action):
    s = dict(state)
    units = {u: dict(v) for u, v in s.get("units", {}).items()}
    incidents = {i: dict(v) for i, v in s.get("incidents", {}).items()}

    name = action.get("name")
    params = action.get("params") or {}

    def waiting_by_priority():
        # most urgent first (lowest priority number), ties broken by id
        pending = [i for i in incidents if incidents[i]["status"] == "waiting"]
        return sorted(pending, key=lambda i: (incidents[i]["priority"], i))

    def first_unit_with(status):
        for u in sorted(units):
            if units[u]["status"] == status:
                return u
        return None

    def tick():
        s["time"] = s.get("time", 0) + 1

    if name == "dispatch":
        unit = params.get("unit") or first_unit_with("idle")
        inc = params.get("incident")
        if inc is None:
            queue = waiting_by_priority()
            inc = queue[0] if queue else None
        if (unit in units and inc in incidents
                and units[unit]["status"] == "idle"
                and incidents[inc]["status"] == "waiting"):
            units[unit]["status"] = "enroute"
            units[unit]["incident"] = inc
            incidents[inc]["status"] = "assigned"
            incidents[inc]["unit"] = unit
            tick()

    elif name == "arrive":
        unit = params.get("unit") or first_unit_with("enroute")
        if unit in units and units[unit]["status"] == "enroute":
            units[unit]["status"] = "onscene"
            inc = units[unit]["incident"]
            if inc in incidents:
                incidents[inc]["status"] = "onscene"
            tick()

    elif name == "return":
        unit = params.get("unit") or first_unit_with("onscene")
        if unit in units and units[unit]["status"] == "onscene":
            inc = units[unit]["incident"]
            if inc in incidents:
                incidents[inc]["status"] = "resolved"
                incidents[inc]["unit"] = None
            units[unit]["status"] = "idle"
            units[unit]["incident"] = None
            s["resolved"] = s.get("resolved", 0) + 1
            tick()

    s["units"] = units
    s["incidents"] = incidents
    s["available"] = sum(1 for u in units if units[u]["status"] == "idle")
    return s

