def perceive(data):
    text = str(data)
    out = {}
    for line in text.split("\n"):
        if ":" not in line:
            continue
        key, val = line.split(":", 1)
        key = key.strip().lower()
        val = val.strip()
        if key == "incident":
            out["incoming_incident"] = val
        elif key == "priority":
            try:
                p = int(val)
            except (ValueError, TypeError):
                continue
            if 1 <= p <= 5:
                out["incoming_priority"] = p
    return out
